import{_ as a,o as s,c as i,ae as o}from"./chunks/framework.BIONGpTb.js";const u=JSON.parse('{"title":"Configuración y Arquitectura del Backend","description":"","frontmatter":{},"headers":[],"relativePath":"backend.md","filePath":"backend.md"}'),t={name:"backend.md"};function n(r,e,l,c,d,p){return s(),i("div",null,[...e[0]||(e[0]=[o(`<h1 id="configuracion-y-arquitectura-del-backend" tabindex="-1">Configuración y Arquitectura del Backend <a class="header-anchor" href="#configuracion-y-arquitectura-del-backend" aria-label="Permalink to &quot;Configuración y Arquitectura del Backend&quot;">​</a></h1><p>El backend de <strong>Structo</strong> está desarrollado en <strong>.NET 10</strong> utilizando C#. Sigue los principios de la <strong>Arquitectura Limpia (Clean Architecture)</strong> y <strong>N-Capas</strong> para asegurar un código mantenible, testeable y desligado de las tecnologías externas.</p><h2 id="🚀-como-levantar-el-entorno-local" tabindex="-1">🚀 Cómo levantar el entorno local <a class="header-anchor" href="#🚀-como-levantar-el-entorno-local" aria-label="Permalink to &quot;🚀 Cómo levantar el entorno local&quot;">​</a></h2><h3 id="_1-preparacion-de-base-de-datos" tabindex="-1">1. Preparación de Base de Datos <a class="header-anchor" href="#_1-preparacion-de-base-de-datos" aria-label="Permalink to &quot;1. Preparación de Base de Datos&quot;">​</a></h3><p>Asegúrate de tener corriendo tus bases de datos (SQL Server y MongoDB). Puedes levantar los contenedores usando el archivo <code>docker-compose.yml</code> (si dispones de él en la raíz o carpeta <code>docker/</code>):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker-compose</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> up</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span></span></code></pre></div><p>O usar tus instancias locales. Asegúrate de configurar las cadenas de conexión correctas en los archivos <code>appsettings.Development.json</code> dentro del proyecto principal.</p><h3 id="_2-ejecutar-migraciones-entity-framework" tabindex="-1">2. Ejecutar Migraciones (Entity Framework) <a class="header-anchor" href="#_2-ejecutar-migraciones-entity-framework" aria-label="Permalink to &quot;2. Ejecutar Migraciones (Entity Framework)&quot;">​</a></h3><p>Entra al proyecto backend y aplica las migraciones a la base de datos SQL Server:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dotnet</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ef</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> database</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --project</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> src/Structo.Infrastructure/Structo.Infrastructure.csproj</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --startup-project</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> src/Structo.WebApi/Structo.WebApi.csproj</span></span></code></pre></div><h3 id="_3-cargar-datos-iniciales-seed" tabindex="-1">3. Cargar Datos Iniciales (Seed) <a class="header-anchor" href="#_3-cargar-datos-iniciales-seed" aria-label="Permalink to &quot;3. Cargar Datos Iniciales (Seed)&quot;">​</a></h3><p>Para poblar la base de datos con información base o de prueba, el ecosistema suele proveer un mecanismo de <em>Seeding</em>. Este suele ejecutarse al inicio de la aplicación dentro de la configuración del <code>Program.cs</code> o usando un endpoint especializado, dependiendo de la configuración actual.</p><p>Si el seed está configurado por inyección o endpoint integrado, simplemente basta con correr el proyecto en modo de desarrollo y/o llamar al endpoint dedicado (por ejemplo, <code>POST /api/seed</code> desde Swagger) para insertar los primeros registros.</p><h3 id="_4-correr-el-proyecto" tabindex="-1">4. Correr el Proyecto <a class="header-anchor" href="#_4-correr-el-proyecto" aria-label="Permalink to &quot;4. Correr el Proyecto&quot;">​</a></h3><p>Levanta la Web API ejecutando el siguiente comando:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dotnet</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --project</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> src/Structo.WebApi/Structo.WebApi.csproj</span></span></code></pre></div><p>El servidor de desarrollo iniciará (usualmente expone una ruta de Swagger en <code>http://localhost:&lt;puerto&gt;/swagger</code>).</p><hr><h2 id="🏗️-patrones-de-diseno-utilizados" tabindex="-1">🏗️ Patrones de Diseño Utilizados <a class="header-anchor" href="#🏗️-patrones-de-diseno-utilizados" aria-label="Permalink to &quot;🏗️ Patrones de Diseño Utilizados&quot;">​</a></h2><p>Durante el desarrollo del backend, se promueve el uso de los siguientes patrones arquitectónicos:</p><ul><li><strong>Inyección de Dependencias (DI)</strong>: Utilizado orgánicamente en .NET Core para inyectar servicios en controladores y otros servicios, promoviendo el bajo acoplamiento.</li><li><strong>Repository Pattern</strong>: Abstracción de acceso a datos provista por las interfaces en el <code>Domain</code> y su implementación en la capa de <code>Infrastructure</code>.</li><li><strong>Data Transfer Objects (DTO)</strong>: Aislando completamente la capa de controladores y los modelos de dominio.</li><li><strong>CQRS (Opcional, según complejidad)</strong>: Separación ligera entre lectura y mutación manejada en la capa de servicios.</li></ul><h2 id="📁-estructura-de-proyectos-n-capas" tabindex="-1">📁 Estructura de Proyectos (N-Capas) <a class="header-anchor" href="#📁-estructura-de-proyectos-n-capas" aria-label="Permalink to &quot;📁 Estructura de Proyectos (N-Capas)&quot;">​</a></h2><p>La solución (<code>Structo.sln</code>) y el directorio <code>src/</code> están divididos conceptualmente:</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">graph TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    API[Structo.WebApi\\nCapa de Presentación] --&gt; S[Structo.Services\\nLógica de Aplicación]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    API --&gt; DTO[Structo.DTO\\nContratos de Datos]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    S --&gt; DOM[Structo.Domain\\nReglas de Negocio / Entidades]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    S --&gt; INF[Structo.Infrastructure\\nAcceso a Datos / EF Core]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    INF --&gt; DOM</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    API -. Inyecta .-&gt; INF</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    </span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style API fill:#2a70d9,stroke:#333,stroke-width:2px,color:#fff</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style S fill:#0b8a4f,stroke:#333,stroke-width:2px,color:#fff</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style INF fill:#d9702a,stroke:#333,stroke-width:2px,color:#fff</span></span></code></pre></div><h3 id="descripcion-de-las-capas" tabindex="-1">Descripción de las Capas <a class="header-anchor" href="#descripcion-de-las-capas" aria-label="Permalink to &quot;Descripción de las Capas&quot;">​</a></h3><ol><li><strong>Structo.WebApi</strong>: Contiene los Controladores (Endpoints HTTP), la configuración del host y el registro de la inyección de dependencias (<code>Program.cs</code>). Responsable de recibir las consultas y delvolver DTOs.</li><li><strong>Structo.Services</strong>: Contiene la lógica de aplicación. Coordina cómo la aplicación interactúa con la base de datos a través de las interfaces y aplica reglas de negocio a gran escala, orquestando mapeos entre Entidades de Dominio y DTOs.</li><li><strong>Structo.Domain</strong>: Es el núcleo del sistema. Contiene las Entidades (modelos de tabla), Enums, Interfaces core y lógica de negocio pura de forma estricta. <strong>No depende de ningún otro proyecto de la solución</strong>.</li><li><strong>Structo.Infrastructure</strong>: Contiene las clases de <code>DbContext</code> (Entity Framework), las implementaciones reales de los repositorios y la configuración hacia bases de datos externas (SQL Server / MongoDB). Depende de <code>Structo.Domain</code>.</li><li><strong>Structo.DTO</strong>: Contiene estructuras planas que transportan los datos solicitados hacia el exterior de la API, evitando exponer directamente las clases del Dominio.</li><li><strong>Structo.Common</strong>: Constantes transversales, excepciones personalizadas compartidas y métodos de extensión para toda la solución.</li></ol>`,26)])])}const g=a(t,[["render",n]]);export{u as __pageData,g as default};
